    {
      "path": "src/modules/projects/routes.js",
      "content": "const express = require('express');
const projectsService = require('./service');
const { randomUUID } = require('../../lib/id');

const router = express.Router();

router.post('/', (req, res) => {
  const { name } = req.body;
  if (!name) {
    return res.status(400).json({ error: { code: 'INVALID_INPUT', message: 'Name is required' } });
  }
  const project = projectsService.createProject(name);
  res.status(201).json({ project });
});

router.get('/', (req, res) => {
  const projects = projectsService.getAllProjects();
  res.json({ projects });
});

router.get('/:projectId', (req, res) => {
  const { projectId } = req.params;
  const project = projectsService.getProjectById(projectId);
  if (!project) {
    return res.status(404).json({ error: { code: 'NOT_FOUND', message: 'Project not found' } });
  }
  res.json({ project });
});

module.exports = router;"
    },
    {
      "path": "src/modules/projects/service.js",
      "content": "let projects = [];

const createProject = (name) => {
  const projectId = randomUUID();
  const project = { id: projectId, name };
  projects.push(project);
  return project;
};

const getAllProjects = () => {
  return projects;
};

const getProjectById = (projectId) => {
  return projects.find(p => p.id === projectId);
};

module.exports = { createProject, getAllProjects, getProjectById };"
    },
    {
      "path": "src/modules/members/routes.js",
      "content": "const express = require('express');
const membersService = require('./service');

const router = express.Router();

router.post('/', (req, res) => {
  const { userId, role } = req.body;
  if (!userId || !role) {
    return res.status(400).json({ error: { code: 'INVALID_INPUT', message: 'User ID and role are required' } });
  }
  const member = membersService.addMember(req.params.projectId, userId, role);
  if (!member) {
    return res.status(409).json({ error: { code: 'DUPLICATE_MEMBER', message: 'Member already exists' } });
  }
  res.status(201).json({ member });
});

router.get('/', (req, res) => {
  const members = membersService.getAllMembers(req.params.projectId);
  if (!members) {
    return res.status(404).json({ error: { code: 'NOT_FOUND', message: 'Project not found' } });
  }
  res.json({ members });
});

module.exports = router;"
    },
    {
      "path": "src/modules/members/service.js",
      "content": "let projectsMembers = {};

const addMember = (projectId, userId, role) => {
  if (!projectsMembers[projectId]) {
    projectsMembers[projectId] = [];
  }
  const existingMember = projectsMembers[projectId].find(m => m.userId === userId);
  if (existingMember) {
    return null;
  }
  const member = { userId, role };
  projectsMembers[projectId].push(member);
  return member;
};

const getAllMembers = (projectId) => {
  return projectsMembers[projectId] || [];
};

module.exports = { addMember, getAllMembers };"
    },
    {
      "path": "src/modules/tasks/routes.js",
      "content": "const express = require('express');
const tasksService = require('./service');

const router = express.Router();

router.post('/', (req, res) => {
  const { title } = req.body;
  if (!title) {
    return res.status(400).json({ error: { code: 'INVALID_INPUT', message: 'Title is required' } });
  }
  const task = tasksService.createTask(req.params.projectId, title);
  res.status(201).json({ task });
});

router.get('/', (req, res) => {
  const tasks = tasksService.getAllTasks(req.params.projectId);
  if (!tasks) {
    return res.status(404).json({ error: { code: 'NOT_FOUND', message: 'Project not found' } });
  }
  res.json({ tasks });
});

router.get('?status=done', (req, res) => {
  const tasks = tasksService.filterTasksByStatus(req.params.projectId, 'done');
  if (!tasks) {
    return res.status(404).json({ error: { code: 'NOT_FOUND', message: 'Project not found' } });
  }
  res.json({ tasks });
});

router.patch('/:taskId', (req, res) => {
  const { status } = req.body;
  if (!status || ![ 'done', 'in-progress', 'not-started' ].includes(status)) {
    return res.status(400).json({ error: { code: 'INVALID_INPUT', message: 'Invalid task status' } });
  }
  const updatedTask = tasksService.updateTaskStatus(req.params.projectId, req.params.taskId, status);
  if (!updatedTask) {
    return res.status(404).json({ error: { code: 'NOT_FOUND', message: 'Task not found' } });
  }
  res.json({ task: updatedTask });
});

module.exports = router;"
    },
    {
      "path": "src/modules/tasks/service.js",
      "content": "let projectsTasks = {};

const createTask = (projectId, title) => {
  if (!projectsTasks[projectId]) {
    projectsTasks[projectId] = [];
  }
  const taskId = randomUUID();
  const task = { id: taskId, title, status: 'not-started' };
  projectsTasks[projectId].push(task);
  return task;
};

const getAllTasks = (projectId) => {
  return projectsTasks[projectId] || [];
};

const filterTasksByStatus = (projectId, status) => {
  const tasks = getAllTasks(projectId);
  if (!tasks) {
    return null;
  }
  return tasks.filter(t => t.status === status);
};

const updateTaskStatus = (projectId, taskId, status) => {
  const tasks = getAllTasks(projectId);
  if (!tasks) {
    return null;
  }
  const task = tasks.find(t => t.id === taskId);
  if (!task) {
    return null;
  }
  task.status = status;
  return task;
};

module.exports = { createTask, getAllTasks, filterTasksByStatus, updateTaskStatus };"
