      "path": "src/modules/comments/routes.js",
      "content": "const express = require('express');
const commentsService = require('./service');

const router = express.Router();

router.post('/', (req, res) => {
  const { content } = req.body;
  if (!content) {
    return res.status(400).json({ error: { code: 'INVALID_INPUT', message: 'Content is required' } });
  }
  const comment = commentsService.addComment(req.params.projectId, req.params.taskId, content);
  res.status(201).json({ comment });
});

router.get('/', (req, res) => {
  const comments = commentsService.getAllComments(req.params.projectId, req.params.taskId);
  if (!comments) {
    return res.status(404).json({ error: { code: 'NOT_FOUND', message: 'Task not found' } });
  }
  res.json({ comments });
});

module.exports = router;"
    },
    {
      "path": "src/modules/comments/service.js",
      "content": "let projectsComments = {};

const addComment = (projectId, taskId, content) => {
  if (!projectsComments[projectId]) {
    projectsComments[projectId] = {};
  }
  if (!projectsComments[projectId][taskId]) {
    projectsComments[projectId][taskId] = [];
  }
  const commentId = randomUUID();
  const comment = { id: commentId, content };
  projectsComments[projectId][taskId].push(comment);
  return comment;
};

const getAllComments = (projectId, taskId) => {
  if (!projectsComments[projectId] || !projectsComments[projectId][taskId]) {
    return null;
  }
  return projectsComments[projectId][taskId];
};

module.exports = { addComment, getAllComments };"
